"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import {
  Cpu,
  Play,
  Edit3,
  Trash2,
  Lock,
  Download,
  Activity,
  CheckCircle2,
  AlertTriangle,
  HelpCircle,
  Plus,
  BarChart3,
  Shield,
  Zap
} from "lucide-react";
import Navbar from "@/components/ui/Navbar";
import { useRegistryStore, PublishedAgent } from "@/stores/registryStore";
import { useLogStore, LogEntry } from "@/stores/useLogStore";
import { useVaultStore } from "@/stores/vaultStore";
import { compileFlow } from "@/lib/flowCompiler";
import { cn } from "@/lib/utils";

export default function DashboardPage() {
  const router = useRouter();
  const { agents, loadAgents, deleteAgent } = useRegistryStore();
  const logs = useLogStore((s) => s.logs);
  const vaultEntries = useVaultStore((s) => s.entries);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    loadAgents();
  }, [loadAgents]);

  if (!mounted) return null;

  // Analytics
  const totalExecutions = agents.reduce((sum, a) => sum + a.totalRuns, 0);
  const totalSuccess = agents.reduce((sum, a) => sum + a.successRuns, 0);
  const successRate = totalExecutions > 0 ? Math.round((totalSuccess / totalExecutions) * 100) : 0;
  const recentLogs = logs.slice(-10).reverse();

  const handleExport = (agent: PublishedAgent, lang: "typescript" | "python") => {
    const code = compileFlow(agent.nodes, agent.edges, lang);
    const ext = lang === "typescript" ? "ts" : "py";
    const blob = new Blob([code], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${agent.name.replace(/\s+/g, "_").toLowerCase()}_agent.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const formatTime = (ts: number) => {
    const d = new Date(ts);
    return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
  };

  const formatDate = (ts: number) => {
    return new Date(ts).toLocaleDateString("en-US", { month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" });
  };

  const logColorMap: Record<string, string> = {
    INFO: "text-slate-400",
    SUCCESS: "text-emerald-400",
    ERROR: "text-rose-400",
    WARN: "text-amber-400",
  };

  return (
    <div className="min-h-screen bg-[#05070a] text-white relative z-10">
      <Navbar />

      <div className="max-w-7xl mx-auto px-6 py-8">
        {/* Page Title */}
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Mission Control</h1>
            <p className="text-sm text-slate-500 mt-1">Agent fleet overview & system diagnostics</p>
          </div>
          <button
            onClick={() => router.push("/editor")}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-bold rounded-xl transition-all shadow-lg shadow-indigo-500/20"
          >
            <Plus size={14} />
            New Agent
          </button>
        </div>

        {/* STATS ROW */}
        <div className="grid grid-cols-4 gap-4 mb-8">
          <StatCard icon={<Cpu size={16} />} label="Published Agents" value={agents.length} color="indigo" />
          <StatCard icon={<Activity size={16} />} label="Total Executions" value={totalExecutions} color="blue" />
          <StatCard icon={<BarChart3 size={16} />} label="Success Rate" value={`${successRate}%`} color="emerald" />
          <StatCard icon={<Lock size={16} />} label="Vault Keys" value={vaultEntries.length} color="cyan" />
        </div>

        {/* BENTO GRID */}
        <div className="grid grid-cols-3 gap-6">

          {/* COLUMN 1: Published Agents */}
          <div className="col-span-1 flex flex-col gap-4">
            <div className="flex items-center gap-2 mb-2">
              <Cpu size={14} className="text-indigo-400" />
              <h2 className="text-xs font-bold uppercase tracking-widest text-slate-500">Published Agents</h2>
            </div>

            {agents.length === 0 ? (
              <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-8 text-center">
                <Zap size={24} className="mx-auto mb-3 text-slate-700" />
                <p className="text-[10px] text-slate-600 uppercase tracking-wider font-bold">No agents published</p>
                <p className="text-[10px] text-slate-700 mt-1 italic">Create and publish an agent from the Editor</p>
              </div>
            ) : (
              agents.map(agent => (
                <div
                  key={agent.id}
                  className="bg-slate-900/50 border border-slate-800 rounded-2xl p-4 hover:border-indigo-500/30 transition-all group"
                >
                  <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 bg-indigo-600/20 rounded-lg flex items-center justify-center">
                        <Cpu size={14} className="text-indigo-400" />
                      </div>
                      <div>
                        <h3 className="text-xs font-bold text-white">{agent.name}</h3>
                        <span className="text-[9px] text-slate-500">{formatDate(agent.publishedAt)}</span>
                      </div>
                    </div>
                    <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button
                        onClick={() => router.push("/editor")}
                        className="p-1.5 rounded-lg hover:bg-slate-800 text-slate-500 hover:text-indigo-400 transition-colors"
                        title="Edit"
                      >
                        <Edit3 size={12} />
                      </button>
                      <button
                        onClick={() => deleteAgent(agent.id)}
                        className="p-1.5 rounded-lg hover:bg-slate-800 text-slate-500 hover:text-rose-400 transition-colors"
                        title="Delete"
                      >
                        <Trash2 size={12} />
                      </button>
                    </div>
                  </div>

                  {/* Stats bar */}
                  <div className="flex items-center gap-4 mb-3">
                    <span className="text-[9px] text-slate-500">
                      <Play size={8} className="inline mr-1" />
                      {agent.totalRuns} runs
                    </span>
                    <span className="text-[9px] text-emerald-500">
                      <CheckCircle2 size={8} className="inline mr-1" />
                      {agent.successRuns} ok
                    </span>
                    <span className="text-[9px] text-slate-500">
                      {agent.nodes.length} nodes
                    </span>
                  </div>

                  {/* Export buttons */}
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => handleExport(agent, "typescript")}
                      className="flex items-center gap-1 px-2.5 py-1 bg-blue-500/10 border border-blue-500/20 text-blue-400 rounded-lg text-[9px] font-bold hover:bg-blue-500/20 transition-all"
                    >
                      <Download size={10} />
                      TypeScript
                    </button>
                    <button
                      onClick={() => handleExport(agent, "python")}
                      className="flex items-center gap-1 px-2.5 py-1 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 rounded-lg text-[9px] font-bold hover:bg-emerald-500/20 transition-all"
                    >
                      <Download size={10} />
                      Python
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>

          {/* COLUMN 2: Recent Logs */}
          <div className="col-span-1 flex flex-col gap-2">
            <div className="flex items-center gap-2 mb-2">
              <Activity size={14} className="text-blue-400" />
              <h2 className="text-xs font-bold uppercase tracking-widest text-slate-500">Recent Events</h2>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden">
              {recentLogs.length === 0 ? (
                <div className="p-8 text-center">
                  <Activity size={24} className="mx-auto mb-3 text-slate-700" />
                  <p className="text-[10px] text-slate-600 uppercase tracking-wider font-bold">No events yet</p>
                  <p className="text-[10px] text-slate-700 mt-1 italic">Run a flow to see activity</p>
                </div>
              ) : (
                <div className="divide-y divide-slate-800/50">
                  {recentLogs.map(log => (
                    <div key={log.id} className="flex items-start gap-3 px-4 py-3 hover:bg-slate-800/30 transition-colors">
                      <div className="mt-0.5">
                        {log.type === "SUCCESS" && <CheckCircle2 size={12} className="text-emerald-400" />}
                        {log.type === "ERROR" && <AlertTriangle size={12} className="text-rose-400" />}
                        {log.type === "INFO" && <Activity size={12} className="text-slate-500" />}
                        {log.type === "WARN" && <Shield size={12} className="text-amber-400" />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className={cn("text-[11px] truncate", logColorMap[log.type] || "text-slate-400")}>
                          {log.message}
                        </p>
                        <span className="text-[9px] text-slate-600">{formatTime(log.timestamp)}</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* COLUMN 3: Vault Status */}
          <div className="col-span-1 flex flex-col gap-2">
            <div className="flex items-center gap-2 mb-2">
              <Lock size={14} className="text-cyan-400" />
              <h2 className="text-xs font-bold uppercase tracking-widest text-slate-500">Security Health</h2>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-4">
              {/* Health summary */}
              <div className={cn(
                "flex items-center gap-3 p-3 rounded-xl border mb-4",
                vaultEntries.length > 0
                  ? "border-emerald-500/20 bg-emerald-500/5"
                  : "border-rose-500/20 bg-rose-500/5"
              )}>
                <div className={cn(
                  "w-3 h-3 rounded-full",
                  vaultEntries.length > 0 ? "bg-emerald-400 animate-pulse" : "bg-rose-400 animate-pulse"
                )} />
                <div>
                  <p className={cn(
                    "text-[10px] font-bold uppercase tracking-wider",
                    vaultEntries.length > 0 ? "text-emerald-400" : "text-rose-400"
                  )}>
                    {vaultEntries.length > 0 ? "Vault Initialized" : "Vault Empty"}
                  </p>
                  <p className="text-[9px] text-slate-500 mt-0.5">
                    {vaultEntries.length} secrets active
                  </p>
                </div>
              </div>

              {/* Key list */}
              <div className="space-y-2">
                {vaultEntries.map(entry => (
                  <div
                    key={entry.key}
                    className="flex items-center justify-between px-3 py-2 bg-[#0b0e14] border border-slate-800 rounded-xl"
                  >
                    <div className="flex items-center gap-2">
                      <Lock size={10} className="text-cyan-400" />
                      <span className="text-[10px] font-mono text-cyan-400">{entry.key}</span>
                    </div>
                    <span className="text-[9px] text-slate-600 font-mono">••••••</span>
                  </div>
                ))}
                {vaultEntries.length === 0 && (
                  <div className="text-center py-4">
                    <p className="text-[10px] text-slate-600 italic">Add secrets in the Editor vault tab</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* HELP FAB */}
      <button
        onClick={() => router.push("/editor")}
        className="fixed bottom-6 right-6 z-50 bg-slate-800/50 backdrop-blur-md p-3 rounded-full border border-slate-700 text-slate-400 hover:text-indigo-400 transition-all shadow-2xl group active:scale-95"
        title="Open Editor"
      >
        <HelpCircle size={20} className="group-hover:rotate-12 transition-transform" />
      </button>
    </div>
  );
}

// --- Stat Card Component ---
function StatCard({ icon, label, value, color }: { icon: React.ReactNode; label: string; value: string | number; color: string }) {
  const colorClasses: Record<string, string> = {
    indigo: "border-indigo-500/20 bg-indigo-500/5 text-indigo-400",
    blue: "border-blue-500/20 bg-blue-500/5 text-blue-400",
    emerald: "border-emerald-500/20 bg-emerald-500/5 text-emerald-400",
    cyan: "border-cyan-500/20 bg-cyan-500/5 text-cyan-400",
  };

  return (
    <div className={cn(
      "rounded-2xl border p-4 flex items-center gap-4 transition-all hover:scale-[1.02]",
      colorClasses[color] || colorClasses.indigo
    )}>
      <div className="p-2.5 rounded-xl bg-slate-900/50">
        {icon}
      </div>
      <div>
        <p className="text-2xl font-bold">{value}</p>
        <p className="text-[9px] font-bold uppercase tracking-widest text-slate-500 mt-0.5">{label}</p>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { 
  Play, 
  Map, 
  Moon, 
  Sun,
  X,
  Zap,
  Rocket,
  HelpCircle,
  ChevronLeft,
  ChevronRight,
  Clock,
  RotateCcw,
  Trash2,
  Terminal
} from "lucide-react";

import FlowCanvas from "@/components/flow/canvas/FlowCanvas";
import NodeSidebar from "@/components/flow/sidebar/NodeSidebar";
import NodeSettingsSidebar from "@/components/flow/sidebar/NodeSettingsSidebar";
import MissionBriefing from "@/components/ui/tutorial/MissionBriefing";
import ResponseGallery from "@/components/flow/ResponseGallery";
import ApprovalBanner from "@/components/flow/ApprovalBanner";

import { useFlowStore, isAwaitingApproval } from "@/stores/flowStore";
import { getSnapshots, saveSnapshot, deleteSnapshot, FlowSnapshot } from "@/lib/versionSnapshots";
import { cn } from "@/lib/utils";
import { useRouter } from "next/navigation";
import { ReactFlowProvider } from "reactflow";

function EditorContent() {
  const router = useRouter();
  const {
    nodes,
    edges,
    setNodes,
    setEdges,
    setSelectedNodeId,
    simulateFlow,
    finalResult,
    setFinalResult,
    showMinimap,
    setShowMinimap,
    theme,
    setTheme,
    tutorialStep,
    setTutorialStep,
    completeTutorial,
    running
  } = useFlowStore();

  const [mounted, setMounted] = useState(false);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(true);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(true);
  const [showVersionMenu, setShowVersionMenu] = useState(false);
  const [snapshots, setSnapshots] = useState<FlowSnapshot[]>([]);
  const [showTerminal, setShowTerminal] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const versionRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setMounted(true);
    const root = window.document.documentElement;
    if (theme === "dark") {
      root.classList.add("dark");
    } else {
      root.classList.remove("dark");
    }

    const hasSeenTutorial = localStorage.getItem('agentforge_onboarding_complete');
    if (!hasSeenTutorial && tutorialStep === 0) {
      setTutorialStep(1);
    }
  }, [theme, setTutorialStep, tutorialStep]);

  useEffect(() => {
    if (tutorialStep === 6 && finalResult) {
      setTutorialStep(7);
    }
  }, [finalResult, tutorialStep, setTutorialStep]);

  // Show terminal when running
  useEffect(() => {
    if (running) setShowTerminal(true);
  }, [running]);

  // Poll for approval state (flash safety alert)
  useEffect(() => {
    if (!running) { setIsPaused(false); return; }
    const interval = setInterval(() => {
      setIsPaused(isAwaitingApproval());
    }, 200);
    return () => clearInterval(interval);
  }, [running]);

  // Close version menu on outside click
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (versionRef.current && !versionRef.current.contains(e.target as Node)) {
        setShowVersionMenu(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  if (!mounted) return null;

  const startNodeId = Array.isArray(nodes) && nodes.length > 0 ? nodes[0].id : "";

  const handleSaveSnapshot = () => {
    const name = `v${snapshots.length + 1} — ${new Date().toLocaleTimeString()}`;
    const snap = saveSnapshot(name, nodes, edges);
    setSnapshots(prev => [snap, ...prev].slice(0, 10));
  };

  const handleRestoreSnapshot = (snap: FlowSnapshot) => {
    setNodes(snap.nodes);
    setEdges(snap.edges);
    setShowVersionMenu(false);
  };

  const handleOpenVersionMenu = () => {
    setSnapshots(getSnapshots());
    setShowVersionMenu(!showVersionMenu);
  };

  const formatTs = (ts: number) => {
    const d = new Date(ts);
    return d.toLocaleString("en-US", { month: "short", day: "numeric", hour: "2-digit", minute: "2-digit", second: "2-digit" });
  };

  return (
    <div className={cn(
      "flex flex-col h-screen w-full transition-colors duration-300",
      theme === "dark" ? "dark bg-[#0b0e14] text-slate-200" : "bg-slate-50 text-slate-900"
    )}>

      {/* HEADER */}
      <header className="flex items-center justify-between border-b border-slate-200 dark:border-slate-800 px-6 py-3 bg-white dark:bg-[#0b0e14] z-50 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Zap size={16} className="text-white fill-current" />
            </div>
            <span className="font-bold tracking-tight text-sm uppercase">AgentForge</span>
          </div>
          <div className="h-4 w-[1px] bg-slate-200 dark:bg-slate-800 mx-2" />
          <span className="text-[10px] text-slate-400 font-medium uppercase tracking-widest hidden md:block">
            Production Environment
          </span>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center p-1 bg-slate-100 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800">
            <HeaderButton onClick={() => setShowMinimap(!showMinimap)} icon={<Map size={14} />} active={showMinimap} />
          </div>

          {/* VERSION HISTORY */}
          <div className="relative" ref={versionRef}>
            <button
              onClick={handleOpenVersionMenu}
              className={cn(
                "p-2.5 rounded-xl border transition-all shadow-sm",
                showVersionMenu
                  ? "bg-indigo-500/10 border-indigo-500/30 text-indigo-400"
                  : "border-slate-200 dark:border-slate-800 hover:bg-slate-100 dark:hover:bg-slate-900 text-slate-500 dark:text-slate-400"
              )}
              title="Version History"
            >
              <Clock size={16} />
            </button>

            {showVersionMenu && (
              <div className="absolute right-0 top-full mt-2 w-72 bg-white dark:bg-[#0b0e14] border border-slate-200 dark:border-slate-700 rounded-xl shadow-2xl z-50 overflow-hidden animate-in slide-in-from-top-1 duration-150">
                <div className="flex items-center justify-between px-4 py-3 border-b border-slate-200 dark:border-slate-700">
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Snapshots</span>
                  <button
                    onClick={handleSaveSnapshot}
                    className="text-[10px] font-bold text-indigo-500 hover:text-indigo-400 transition-colors"
                  >
                    + Save Now
                  </button>
                </div>
                <div className="max-h-64 overflow-y-auto">
                  {snapshots.length === 0 ? (
                    <div className="px-4 py-6 text-center text-[10px] text-slate-500 italic">
                      No snapshots yet
                    </div>
                  ) : (
                    snapshots.map((snap) => (
                      <div
                        key={snap.id}
                        className="flex items-center justify-between px-4 py-2.5 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group cursor-pointer border-b border-slate-100 dark:border-slate-800 last:border-0"
                      >
                        <div onClick={() => handleRestoreSnapshot(snap)} className="flex-1 flex flex-col">
                          <span className="text-xs font-medium text-slate-700 dark:text-slate-300">{snap.name}</span>
                          <span className="text-[9px] text-slate-400">{formatTs(snap.timestamp)} · {snap.nodes.length} nodes</span>
                        </div>
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button
                            onClick={() => handleRestoreSnapshot(snap)}
                            className="p-1 text-indigo-400 hover:text-indigo-300"
                            title="Restore"
                          >
                            <RotateCcw size={12} />
                          </button>
                          <button
                            onClick={() => { deleteSnapshot(snap.id); setSnapshots(prev => prev.filter(s => s.id !== snap.id)); }}
                            className="p-1 text-slate-500 hover:text-rose-400"
                            title="Delete"
                          >
                            <Trash2 size={12} />
                          </button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>

          <div className="flex items-center gap-2 ml-2">
            <button
                onClick={() => simulateFlow(startNodeId)}
                className={cn(
                  "flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all",
                  tutorialStep === 6 
                    ? "bg-indigo-600 hover:bg-indigo-500 text-white ring-4 ring-indigo-500/40 animate-[pulse_1.5s_ease-in-out_infinite] shadow-[0_0_20px_rgba(99,102,241,0.5)] z-10" 
                    : "bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-500/20"
                )}
            >
                <Play size={14} className="fill-current" />
                Run Flow
            </button>

            <button
                onClick={() => {
                  completeTutorial();
                  router.push('/publish');
                }}
                className={cn(
                "flex items-center gap-2 px-4 py-2 transition-all rounded-xl text-xs font-bold",
                (tutorialStep === 7 && finalResult)
                    ? "bg-emerald-500 hover:bg-emerald-400 text-white ring-4 ring-emerald-500/40 animate-[pulse_1.5s_ease-in-out_infinite] shadow-[0_0_20px_rgba(16,185,129,0.5)] z-10" 
                    : "bg-emerald-500 hover:bg-emerald-600 text-white shadow-lg shadow-emerald-500/20"
                )}
            >
                <Rocket size={14} />
                Publish & Export
            </button>
          </div>

          <button
            onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
            className="p-2.5 rounded-xl border border-slate-200 dark:border-slate-800 hover:bg-slate-100 dark:hover:bg-slate-900 transition-all text-slate-500 dark:text-slate-400 shadow-sm"
          >
            {theme === "dark" ? <Sun size={18} /> : <Moon size={18} />}
          </button>
        </div>
      </header>

      {/* MAIN CONTENT AREA */}
      <div className="flex flex-1 overflow-hidden relative">

        {/* LEFT SIDEBAR TOGGLE */}
        <button
          onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
          className={cn(
            "absolute top-1/2 -translate-y-1/2 z-50 p-2 rounded-full border transition-all shadow-lg backdrop-blur-sm",
            "bg-slate-800/80 border-slate-700/50 text-white hover:bg-slate-700",
            isLeftSidebarOpen ? "left-[252px]" : "left-2"
          )}
          title={isLeftSidebarOpen ? "Collapse Nodes" : "Expand Nodes"}
        >
          {isLeftSidebarOpen ? <ChevronLeft size={16} /> : <ChevronRight size={16} />}
        </button>

        {/* LEFT SIDEBAR */}
        <AnimatePresence initial={false}>
          {isLeftSidebarOpen && (
            <motion.aside
              initial={{ width: 0, opacity: 0 }}
              animate={{ width: 256, opacity: 1 }}
              exit={{ width: 0, opacity: 0 }}
              transition={{ type: "spring", stiffness: 300, damping: 30 }}
